const ethers = require('ethers');

// Wallet configuration with private key
const privateKey = 'your-private-key-here';
const provider = new ethers.providers.JsonRpcProvider('https://mainnet.infura.io/v3/your-infura-project-id');
const wallet = new ethers.Wallet(privateKey, provider);

// Function to send ETH
async function sendETH(toAddress, amountInEther) {
    const tx = {
        to: toAddress,
        value: ethers.utils.parseEther(amountInEther),
        gasLimit: 21000,
        gasPrice: await provider.getGasPrice(),
    };
    const transactionResponse = await wallet.sendTransaction(tx);
    return transactionResponse;
}

// Function to interact with a smart contract
async function interactWithContract(contractAddress, abi, functionName, params) {
    const contract = new ethers.Contract(contractAddress, abi, wallet);
    const transactionResponse = await contract[functionName](...params);
    return transactionResponse;
}

